external_knowledge:
; Template usage implies the frequency at which a template is utilized; 
; Projects are considered active, completed, or on hold as indicated by their statuses; 
; Template versions are considered approved if 'approved' equals 1; 
; Feedback is considered resolved if 'is_resolved' equals 1; 
; Ratings are provided on a scale of 1-5.

sql:
SELECT session_id, COUNT(template_id) AS number_of_templates
FROM template_training
GROUP BY session_id;

SELECT template_name
FROM templates
WHERE usage_count = (SELECT MAX(usage_count) FROM templates);
